Here's a minimal API endpoint handling multipart form uploads with multiple images and a description:

```csharp
using Microsoft.AspNetCore.Http.Features;

var builder = WebApplication.CreateBuilder(args);

// Raise the max request body size to 50 MB
builder.WebHost.ConfigureKestrel(o =>
    o.Limits.MaxRequestBodySize = 50 * 1024 * 1024);

var app = builder.Build();

app.MapPost("/upload", async (HttpRequest request) =>
{
    // Ensure it's a multipart/form-data request
    if (!request.HasFormContentType)
        return Results.BadRequest("Expected a multipart/form-data request.");

    var form = await request.ReadFormAsync();
    var description = form["description"].ToString();
    var files = form.Files.GetFiles("images");

    if (files.Count == 0)
        return Results.BadRequest("No image files provided.");

    var saved = new List<string>();

    foreach (var file in files)
    {
        // Validate content type
        if (!file.ContentType.StartsWith("image/"))
            return Results.BadRequest($"'{file.FileName}' is not an image.");

        var dest = Path.Combine("uploads", Guid.NewGuid() + Path.GetExtension(file.FileName));
        Directory.CreateDirectory("uploads");

        await using var stream = File.Create(dest);
        await file.CopyToAsync(stream);
        saved.Add(dest);
    }

    return Results.Ok(new { description, fileCount = saved.Count, paths = saved });
})
.DisableAntiforgery()                       // required for form posts without CSRF tokens
.WithRequestFormLimits(                     // per-endpoint form limits
    multipartBodyLengthLimit: 50 * 1024 * 1024,
    valueCountLimit: 64);

app.Run();
```

**Key pieces:**

| Concern | How it's handled |
|---|---|
| **Max body size** | `KestrelServerOptions.Limits.MaxRequestBodySize` (server-wide) |
| **Max form size** | `.WithRequestFormLimits()` (per-endpoint) |
| **Multiple files** | `form.Files.GetFiles("images")` — matches the form field name |
| **Text field** | `form["description"]` — reads a regular form value |
| **CSRF** | `.DisableAntiforgery()` — needed for API-style form posts |

A matching `curl` call:

```bash
curl -F "description=Beach photos" \
     -F "images=@photo1.jpg"       \
     -F "images=@photo2.png"       \
     http://localhost:5000/upload
```
